INSERT INTO `configuracion` VALUES
('direccion_empresa','Ñemby - Santa Rosa c/ tte 1ro Ruben Guido','Dirección fiscal','2026-01-20 15:06:51'),
('iva_incluido','1','Si los precios incluyen IVA',NULL),
('moneda','PYG','Moneda del sistema',NULL),
('nombre_empresa','RYJCELL','Nombre de la empresa','2026-01-20 15:06:51'),
('ruc_empresa','7218272-5','RUC de la empresa','2026-01-20 15:06:51'),
('stock_negativo_permitido','0','Permitir vender sin stock',NULL),
('telefono_empresa','0981693161','Teléfono de contacto','2026-01-20 15:06:51'),
('ticket_footer_text','GRACIAS POR SU COMPRA VUELVA PRONTO','Texto del pie del ticket','2026-01-20 15:06:51'),
('ticket_template_html','<!doctype html>\r\n<html lang=\"es\">\r\n\r\n<head>\r\n    <meta charset=\"utf-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\r\n    <title>Ticket Venta #{{ venta.id_venta }}</title>\r\n    <style>\r\n        /* Reset agresivo para impresoras termicas */\r\n        @page {\r\n            size: 58mm auto;\r\n            margin: 0;\r\n        }\r\n\r\n        * {\r\n            margin: 0;\r\n            padding: 0;\r\n            box-sizing: border-box;\r\n        }\r\n\r\n        html,\r\n        body {\r\n            width: 58mm;\r\n            max-width: 58mm;\r\n            margin: 0;\r\n            padding: 0;\r\n            background: #fff !important;\r\n            color: #000 !important;\r\n            font-family: \'Courier New\', Courier, monospace;\r\n            font-size: 11px;\r\n            line-height: 1.3;\r\n        }\r\n\r\n        body {\r\n            padding: 2mm;\r\n        }\r\n\r\n        /* Estilos para tablas - compatibles con impresoras termicas */\r\n        table {\r\n            width: 100%;\r\n            border-collapse: collapse;\r\n            table-layout: fixed;\r\n        }\r\n\r\n        td,\r\n        th {\r\n            padding: 1px 0;\r\n            vertical-align: top;\r\n            word-wrap: break-word;\r\n            overflow-wrap: break-word;\r\n        }\r\n\r\n        .center {\r\n            text-align: center;\r\n        }\r\n\r\n        .right {\r\n            text-align: right;\r\n        }\r\n\r\n        .left {\r\n            text-align: left;\r\n        }\r\n\r\n        .bold {\r\n            font-weight: bold;\r\n        }\r\n\r\n        .small {\r\n            font-size: 10px;\r\n        }\r\n\r\n        .muted {\r\n            color: #333;\r\n        }\r\n\r\n        /* Separador simple con guiones */\r\n        .sep {\r\n            border: none;\r\n            border-top: 1px dashed #000;\r\n            margin: 4px 0;\r\n            height: 0;\r\n        }\r\n\r\n        /* Encabezado empresa */\r\n        .header {\r\n            text-align: center;\r\n            margin-bottom: 4px;\r\n        }\r\n\r\n        .header .nombre {\r\n            font-size: 13px;\r\n            font-weight: bold;\r\n        }\r\n\r\n        /* Sin flex - todo con tablas */\r\n        .info-row td {\r\n            padding: 1px 0;\r\n        }\r\n\r\n        .info-label {\r\n            width: 35%;\r\n        }\r\n\r\n        .info-value {\r\n            width: 65%;\r\n        }\r\n\r\n        /* Columnas productos */\r\n        .col-prod {\r\n            width: 50%;\r\n        }\r\n\r\n        .col-cant {\r\n            width: 15%;\r\n            text-align: right;\r\n        }\r\n\r\n        .col-total {\r\n            width: 35%;\r\n            text-align: right;\r\n        }\r\n\r\n        /* No imprimir ciertos elementos */\r\n        @media print {\r\n\r\n            html,\r\n            body {\r\n                width: 58mm !important;\r\n                max-width: 58mm !important;\r\n                background: #fff !important;\r\n                color: #000 !important;\r\n            }\r\n        }\r\n    </style>\r\n</head>\r\n\r\n<body>\r\n    <!-- ENCABEZADO EMPRESA -->\r\n    <div class=\"header\">\r\n        {% if empresa.nombre %}\r\n        <div class=\"nombre\">{{ empresa.nombre|thermal_safe }}</div>\r\n        {% endif %}\r\n        {% if empresa.ruc %}\r\n        <div class=\"small\">RUC: {{ empresa.ruc|thermal_safe }}</div>\r\n        {% endif %}\r\n        {% if empresa.telefono %}\r\n        <div class=\"small\">Tel: {{ empresa.telefono|thermal_safe }}</div>\r\n        {% endif %}\r\n        {% if empresa.direccion %}\r\n        <div class=\"small\">{{ empresa.direccion|thermal_safe }}</div>\r\n        {% endif %}\r\n    </div>\r\n\r\n    <hr class=\"sep\" />\r\n\r\n    <!-- INFO VENTA -->\r\n    <table>\r\n        <tr class=\"info-row\">\r\n            <td class=\"info-label\">Venta:</td>\r\n            <td class=\"info-value\">#{{ venta.id_venta }}</td>\r\n        </tr>\r\n        <tr class=\"info-row\">\r\n            <td class=\"info-label\">Fecha:</td>\r\n            <td class=\"info-value\">{{ venta.fecha_venta|local_strftime(\'%d/%m/%Y %H:%M\') }}</td>\r\n        </tr>\r\n        <tr class=\"info-row\">\r\n            <td class=\"info-label\">Cliente:</td>\r\n            <td class=\"info-value\">{{ venta.cliente.nombre|thermal_safe }}</td>\r\n        </tr>\r\n        <tr class=\"info-row\">\r\n            <td class=\"info-label\">Vendedor:</td>\r\n            <td class=\"info-value\">{{ (venta.sesion_caja.usuario.nombre_completo if venta.sesion_caja and venta.sesion_caja.usuario else \'Desconocido\')|thermal_safe }}</td>\r\n        </tr>\r\n    </table>\r\n\r\n    <hr class=\"sep\" />\r\n\r\n    <!-- PRODUCTOS -->\r\n    <table>\r\n        <thead>\r\n            <tr>\r\n                <th class=\"left col-prod\">Producto</th>\r\n                <th class=\"right col-cant\">Cant</th>\r\n                <th class=\"right col-total\">Total</th>\r\n            </tr>\r\n        </thead>\r\n        <tbody>\r\n            {% for item in detalles %}\r\n            <tr>\r\n                <td class=\"col-prod\">\r\n                    {{ item.producto.nombre|thermal_safe }}<br />\r\n                    <span class=\"small muted\">{{ moneda_simbolo }} {{\r\n                        \"{:,.0f}\".format(item.precio_unitario).replace(\",\", \".\") }}</span>\r\n                </td>\r\n                <td class=\"right col-cant\">{{ item.cantidad }}</td>\r\n                <td class=\"right col-total\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(item.subtotal).replace(\",\", \".\") }}\r\n                </td>\r\n            </tr>\r\n            {% endfor %}\r\n        </tbody>\r\n    </table>\r\n\r\n    <hr class=\"sep\" />\r\n\r\n    <!-- TOTALES -->\r\n    <table>\r\n        <tr>\r\n            <td class=\"left\">Subtotal</td>\r\n            <td class=\"right\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(subtotal).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n        {% if descuento and descuento > 0 %}\r\n        <tr>\r\n            <td class=\"left\">Descuento</td>\r\n            <td class=\"right\">- {{ moneda_simbolo }} {{ \"{:,.0f}\".format(descuento).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n        {% endif %}\r\n        <tr>\r\n            <td class=\"left bold\">TOTAL</td>\r\n            <td class=\"right bold\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(venta.total).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n    </table>\r\n\r\n    <hr class=\"sep\" />\r\n\r\n    <!-- TOTALES PAGADOS -->\r\n    <table>\r\n        <tr>\r\n            <td class=\"left\">Pagado</td>\r\n            <td class=\"right\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(total_pagado).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n        {% if vuelto and vuelto > 0 %}\r\n        <tr>\r\n            <td class=\"left\">Vuelto</td>\r\n            <td class=\"right\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(vuelto).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n        {% endif %}\r\n    </table>\r\n\r\n    <!-- DETALLE DE PAGOS -->\r\n    {% if pagos_resumen and pagos_resumen|length > 0 %}\r\n    <hr class=\"sep\" />\r\n    <div class=\"small\">Pagos:</div>\r\n    <table>\r\n        {% for pago in pagos_resumen %}\r\n        <tr>\r\n            <td class=\"left\">{{ pago.nombre|thermal_safe }}</td>\r\n            <td class=\"right\">{{ moneda_simbolo }} {{ \"{:,.0f}\".format(pago.monto).replace(\",\", \".\") }}</td>\r\n        </tr>\r\n        {% if pago.referencias and pago.referencias|length > 0 %}\r\n        <tr>\r\n            <td colspan=\"2\" class=\"small muted\">Ref: {{ pago.referencias|join(\', \')|thermal_safe }}</td>\r\n        </tr>\r\n        {% endif %}\r\n        {% endfor %}\r\n    </table>\r\n    {% endif %}\r\n\r\n    <hr class=\"sep\" />\r\n\r\n    <!-- PIE -->\r\n    <div class=\"center small\">\r\n        {{ footer_text|default(\'Gracias por su compra\')|thermal_safe }}\r\n    </div>\r\n\r\n    <!-- ESPACIO EXTRA para que la impresora no corte el texto final -->\r\n    <!-- Las impresoras térmicas necesitan margen de avance de papel -->\r\n    <div style=\"height: 15mm;\"></div>\r\n    <br /><br /><br />\r\n\r\n    <!-- SCRIPT DE IMPRESION -->\r\n    {% if not preview and not embedded %}\r\n    <script>\r\n        window.onload = function () {\r\n            setTimeout(function () {\r\n                window.print();\r\n            }, 500);\r\n        };\r\n        window.onafterprint = function () {\r\n            window.close();\r\n        };\r\n    </script>\r\n    {% endif %}\r\n</body>\r\n\r\n</html>\r\n','Plantilla HTML del ticket','2026-01-20 15:06:51');
